import VueRouter from 'vue-router'
//引入组件
import Index from '../pages'
import Home from '../pages/home/home'
import Login from '../pages/login/login'
import Register from '../pages/register/register'
import Center from '../pages/center/center'
import Messages from '../pages/messages/list'
import Storeup from '../pages/storeup/list'
import payList from '../pages/pay'

import musicinfoList from '../pages/musicinfo/list'
import musicinfoDetail from '../pages/musicinfo/detail'
import musicinfoAdd from '../pages/musicinfo/add'
import yonghuList from '../pages/yonghu/list'
import yonghuDetail from '../pages/yonghu/detail'
import yonghuAdd from '../pages/yonghu/add'
import musicinfoforecastList from '../pages/musicinfoforecast/list'
import musicinfoforecastDetail from '../pages/musicinfoforecast/detail'
import musicinfoforecastAdd from '../pages/musicinfoforecast/add'
import News from '../pages/news/news-list'
import NewsDetail from '../pages/news/news-detail'
import discussmusicinfoList from '../pages/discussmusicinfo/list'
import discussmusicinfoDetail from '../pages/discussmusicinfo/detail'
import discussmusicinfoAdd from '../pages/discussmusicinfo/add'

const originalPush = VueRouter.prototype.push
VueRouter.prototype.push = function push(location) {
	return originalPush.call(this, location).catch(err => err)
}

//配置路由
export default new VueRouter({
	routes:[
		{
      path: '/',
      redirect: '/index/home'
    },
		{
			path: '/index',
			component: Index,
			children:[
				{
					path: 'home',
					component: Home
				},
				{
					path: 'center',
					component: Center,
				},
				{
					path: 'pay',
					component: payList,
				},
				{
					path: 'messages',
					component: Messages
				},
				{
					path: 'storeup',
					component: Storeup
				},
				{
					path: 'musicinfo',
					component: musicinfoList
				},
				{
					path: 'musicinfoDetail',
					component: musicinfoDetail
				},
				{
					path: 'musicinfoAdd',
					component: musicinfoAdd
				},
				{
					path: 'yonghu',
					component: yonghuList
				},
				{
					path: 'yonghuDetail',
					component: yonghuDetail
				},
				{
					path: 'yonghuAdd',
					component: yonghuAdd
				},
				{
					path: 'musicinfoforecast',
					component: musicinfoforecastList
				},
				{
					path: 'musicinfoforecastDetail',
					component: musicinfoforecastDetail
				},
				{
					path: 'musicinfoforecastAdd',
					component: musicinfoforecastAdd
				},
				{
					path: 'news',
					component: News
				},
				{
					path: 'newsDetail',
					component: NewsDetail
				},
				{
					path: 'discussmusicinfo',
					component: discussmusicinfoList
				},
				{
					path: 'discussmusicinfoDetail',
					component: discussmusicinfoDetail
				},
				{
					path: 'discussmusicinfoAdd',
					component: discussmusicinfoAdd
				},
			]
		},
		{
			path: '/login',
			component: Login
		},
		{
			path: '/register',
			component: Register
		},
	]
})
